46	void ULFPShopWidget::RefreshRelicList()
47	{
48		RelicButtons.Empty();
49		ButtonToRelicIndexMap.Empty();
50	
51		if (Box_RelicList)
52		{
53			Box_RelicList->ClearChildren();
54		}
55	
56		if (!CachedGameInstance || !Box_RelicList)
57		{
58			return;
59		}
60	
61		for (int32 i = 0; i < CachedShopDefinition.RelicList.Num(); ++i)
62		{
63			const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[i];
64			FLFPRelicDefinition RelicDefinition;
65			if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, RelicDefinition))
66			{
67				continue;
68			}
69	
70			UButton* RelicButton = NewObject<UButton>(this);
71			if (!RelicButton)
72			{
73				continue;
74			}
75	
76			UTextBlock* Label = NewObject<UTextBlock>(RelicButton);
77			if (Label)
78			{
79				FString Suffix;
80				if (CachedGameInstance->HasRelic(Entry.RelicID))
81				{
82					Suffix = TEXT(" [已拥有]");
83				}
84				else if (!CachedGameInstance->CanAffordGold(Entry.Price))
85				{
86					Suffix = TEXT(" [金币不足]");
87				}
88	
89				Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *RelicDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
90				RelicButton->AddChild(Label);
91			}
92	
93			UVerticalBoxSlot* ItemSlot = Box_RelicList->AddChildToVerticalBox(RelicButton);
94			if (ItemSlot)
95			{
96				ItemSlot->SetPadding(FMargin(4.f));
97			}
98	
99			RelicButton->OnClicked.AddDynamic(this, &ULFPShopWidget::OnRelicButtonClicked);
100			RelicButtons.Add(RelicButton);
101			ButtonToRelicIndexMap.Add(RelicButton, i);
102		}
103	}
104	
105	void ULFPShopWidget::RefreshOwnedRelicList()
106	{
107		if (!Box_OwnedRelicList)
108		{
109			return;
110		}
111	
112		Box_OwnedRelicList->ClearChildren();
113	
114		if (!CachedGameInstance)
115		{
116			return;
117		}
118	
119		const TArray<FName> OwnedRelicIDs = CachedGameInstance->GetOwnedRelicIDsArray();
120		if (OwnedRelicIDs.Num() == 0)
121		{
122			UTextBlock* EmptyText = NewObject<UTextBlock>(Box_OwnedRelicList);
123			if (EmptyText)
124			{
125				EmptyText->SetText(FText::FromString(TEXT("尚未拥有遗物")));
126				Box_OwnedRelicList->AddChildToVerticalBox(EmptyText);
127			}
128			return;
129		}
130	
131		for (const FName& RelicID : OwnedRelicIDs)
132		{
133			FLFPRelicDefinition Definition;
134			if (!CachedGameInstance->FindRelicDefinition(RelicID, Definition))
135			{
136				continue;
137			}
138	
139			UTextBlock* OwnedText = NewObject<UTextBlock>(Box_OwnedRelicList);
140			if (!OwnedText)
141			{
142				continue;
143			}
144	
145			OwnedText->SetText(FText::FromString(FString::Printf(TEXT("%s"), *Definition.DisplayName.ToString())));
146			UVerticalBoxSlot* OwnedSlot = Box_OwnedRelicList->AddChildToVerticalBox(OwnedText);
147			if (OwnedSlot)
148			{
149				OwnedSlot->SetPadding(FMargin(4.f, 2.f));
150			}
151		}
152	}
153	
154	void ULFPShopWidget::RefreshDetailPanel()
155	{
156		if (!CachedGameInstance)
157		{
158			return;
159		}
160	
161		if (!CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
162		{
163			if (Text_SelectedName) Text_SelectedName->SetText(FText::FromString(TEXT("未选择遗物")));
164			if (Text_SelectedDescription) Text_SelectedDescription->SetText(FText::GetEmpty());
165			if (Text_SelectedPrice) Text_SelectedPrice->SetText(FText::GetEmpty());
166			if (Text_Status) Text_Status->SetText(FText::GetEmpty());
167			if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
168			if (Image_SelectedRelic) Image_SelectedRelic->SetBrushFromTexture(nullptr);
169			return;
170		}
171	
172		const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
173		FLFPRelicDefinition Definition;
174		if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, Definition))
175		{
176			if (Text_Status) Text_Status->SetText(FText::FromString(TEXT("遗物定义缺失")));
177			if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
178			return;
179		}
180	
181		if (Image_SelectedRelic)
182		{
183			Image_SelectedRelic->SetBrushFromTexture(Definition.Icon);
184		}
185		if (Text_SelectedName)
186		{
187			Text_SelectedName->SetText(Definition.DisplayName);
188		}
189		if (Text_SelectedDescription)
190		{
191			Text_SelectedDescription->SetText(FText::FromString(FString::Printf(TEXT("%s\n%s"), *Definition.Description.ToString(), *BuildEffectDescription(Definition))));
192		}
193		if (Text_SelectedPrice)
194		{
195			Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
196		}
197	
198		bool bOwned = CachedGameInstance->HasRelic(Entry.RelicID);
199		bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
200		if (Button_Purchase)
201		{
202			Button_Purchase->SetIsEnabled(!bOwned && bCanAfford);
203		}
204		if (Text_Status)
205		{
206			if (bOwned)
207			{
208				Text_Status->SetText(FText::FromString(TEXT("已拥有")));
209			}
210			else if (!bCanAfford)
211			{
212				Text_Status->SetText(FText::FromString(TEXT("金币不足")));
213			}
214			else
215			{
216				Text_Status->SetText(FText::FromString(TEXT("可购买")));
217			}
218		}
219	}
