221	FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
222	{
223		TArray<FString> Parts;
224		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
225		{
226			switch (Effect.EffectType)
227			{
228			case ELFPRelicEffectType::RET_MaxHealthFlat:
229				Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
230				break;
231			case ELFPRelicEffectType::RET_AttackFlat:
232				Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
233				break;
234			case ELFPRelicEffectType::RET_DefenseFlat:
235				Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
236				break;
237			case ELFPRelicEffectType::RET_SpeedFlat:
238				Parts.Add(FString::Printf(TEXT("速度 %+d"), Effect.Value));
239				break;
240			default:
241				break;
242			}
243		}
244	
245		return Parts.Num() > 0 ? FString::Join(Parts, TEXT("\n")) : TEXT("无效果");
246	}
247	
248	void ULFPShopWidget::OnRelicButtonClicked()
249	{
250		for (const auto& Pair : ButtonToRelicIndexMap)
251		{
252			if (Pair.Key && Pair.Key->IsHovered())
253			{
254				SelectedRelicIndex = Pair.Value;
255				RefreshDetailPanel();
256				return;
257			}
258		}
259	}
260	
261	void ULFPShopWidget::OnPurchaseClicked()
262	{
263		if (!CachedGameInstance || !CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
264		{
265			return;
266		}
267	
268		const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
269		if (CachedGameInstance->TryPurchaseRelic(Entry.RelicID, Entry.Price))
270		{
271			RefreshShopUI();
272		}
273	}
274	
275	void ULFPShopWidget::OnCloseClicked()
276	{
277		SetVisibility(ESlateVisibility::Collapsed);
278		RemoveFromParent();
279		OnClosed.Broadcast();
280	}
