17	void ULFPDeploymentWidget::Setup(const TArray<FLFPUnitEntry>& PartyUnits, ULFPUnitRegistryDataAsset* Registry)
18	{
19		CachedPartyUnits = PartyUnits;
20		UnitRegistry = Registry;
21	
22		// 初始化放置状态
23		PlacedStates.Empty();
24		PlacedStates.SetNum(3);
25		for (int32 i = 0; i < 3; i++)
26		{
27			PlacedStates[i] = false;
28		}
29	
30		bConfirmEnabled = false;
31	
32		// 设置各槽位图标和可见性
33		for (int32 i = 0; i < 3; i++)
34		{
35			UButton* Btn = GetUnitButton(i);
36			UImage* Img = GetUnitImage(i);
37	
38			if (i < PartyUnits.Num() && PartyUnits[i].IsValid() && Registry)
39			{
40				// 有单位：显示按钮，设置图标
41				if (Btn) Btn->SetVisibility(ESlateVisibility::Visible);
42	
43				FLFPUnitRegistryEntry Entry;
44				if (Img && Registry->FindEntry(PartyUnits[i].TypeID, Entry) && Entry.Icon)
45				{
46					Img->SetBrushFromTexture(Entry.Icon);
47					Img->SetVisibility(ESlateVisibility::Visible);
48				}
49			}
50			else
51			{
52				// 无单位：隐藏按钮
53				if (Btn) Btn->SetVisibility(ESlateVisibility::Collapsed);
54			}
55		}
56	
57		// 确认按钮初始禁用
58		if (Button_Confirm)
59		{
60			Button_Confirm->SetIsEnabled(false);
61		}
62	}
63	
64	void ULFPDeploymentWidget::MarkUnitPlaced(int32 PartyIndex, bool bPlaced)
65	{
66		if (!PlacedStates.IsValidIndex(PartyIndex)) return;
67	
68		PlacedStates[PartyIndex] = bPlaced;
69		UpdateSlotVisual(PartyIndex);
70	
71		// 检查是否全部放置完毕
72		bool bAllPlaced = true;
73		for (int32 i = 0; i < CachedPartyUnits.Num() && i < PlacedStates.Num(); i++)
74		{
75			if (CachedPartyUnits[i].IsValid() && !PlacedStates[i])
76			{
77				bAllPlaced = false;
78				break;
79			}
80		}
81		SetConfirmEnabled(bAllPlaced);
82	}
83	
84	void ULFPDeploymentWidget::SetConfirmEnabled(bool bEnabled)
85	{
86		bConfirmEnabled = bEnabled;
87		if (Button_Confirm)
88		{
89			Button_Confirm->SetIsEnabled(bEnabled);
90		}
91	}
92	
93	void ULFPDeploymentWidget::MarkUnitSelecting(int32 PartyIndex)
94	{
95		// 可扩展：高亮正在放置的槽位
96	}
97	
98	void ULFPDeploymentWidget::UpdateSlotVisual(int32 Index)
99	{
100		UImage* Img = GetUnitImage(Index);
101		UButton* Btn = GetUnitButton(Index);
102	
103		bool bPlaced = PlacedStates.IsValidIndex(Index) && PlacedStates[Index];
104	
105		// 已放置：禁用按钮，防止重复生成
106		if (Btn)
107		{
108			Btn->SetIsEnabled(!bPlaced);
109		}
110	
111		if (Img)
112		{
113			if (bPlaced)
114			{
115				// 已放置：半透明
116				Img->SetColorAndOpacity(FLinearColor(0.5f, 0.5f, 0.5f, 0.5f));
117			}
118			else
119			{
120				// 未放置：正常
121				Img->SetColorAndOpacity(FLinearColor::White);
122			}
123		}
124	}
