7	void ULFPTeleportWidget::NativeOnInitialized()
8	{
9		Super::NativeOnInitialized();
10	
11		if (Button_Close) Button_Close->OnClicked.AddDynamic(this, &ULFPTeleportWidget::OnCloseClicked);
12	}
13	
14	void ULFPTeleportWidget::Setup(const TArray<ALFPWorldMapNode*>& TargetNodes)
15	{
16		// 清理旧按钮
17		for (UButton* Btn : DestinationButtons)
18		{
19			if (Btn && Btn->GetParent())
20			{
21				Btn->RemoveFromParent();
22			}
23		}
24		DestinationButtons.Empty();
25		ButtonToNodeIDMap.Empty();
26	
27		if (!Box_DestinationList) return;
28	
29		Box_DestinationList->ClearChildren();
30	
31		for (ALFPWorldMapNode* Node : TargetNodes)
32		{
33			if (!Node) continue;
34	
35			// 创建按钮
36			UButton* Btn = NewObject<UButton>(this);
37			if (!Btn) continue;
38	
39			// 创建按钮内文字
40			UTextBlock* Label = NewObject<UTextBlock>(Btn);
41			if (Label)
42			{
43				Label->SetText(FText::FromString(FString::Printf(TEXT("城镇 %d"), Node->NodeID)));
44			}
45	
46			Btn->AddChild(Label);
47			Btn->OnClicked.AddDynamic(this, &ULFPTeleportWidget::OnDestinationClicked);
48	
49			Box_DestinationList->AddChild(Btn);
50			DestinationButtons.Add(Btn);
51			ButtonToNodeIDMap.Add(Btn, Node->NodeID);
52		}
53	
54		if (TargetNodes.Num() == 0 && Text_Title)
55		{
56			Text_Title->SetText(FText::FromString(TEXT("没有可传送的目的地")));
57		}
58		else if (Text_Title)
59		{
60			Text_Title->SetText(FText::FromString(TEXT("选择传送目的地")));
61		}
62	}
63	
64	void ULFPTeleportWidget::OnDestinationClicked()
65	{
66		// 查找被点击的按钮
67		for (const auto& Pair : ButtonToNodeIDMap)
68		{
69			if (Pair.Key && Pair.Key->IsPressed())
70			{
71				OnTeleportTargetSelected.Broadcast(Pair.Value);
72				return;
73			}
74		}
75	}
76	
77	void ULFPTeleportWidget::OnCloseClicked()
78	{
79		SetVisibility(ESlateVisibility::Collapsed);
80		RemoveFromParent();
81		OnClosed.Broadcast();
82	}
