92	void ULFPHealthBarWidget::UpdateAffiliationColor(EUnitAffiliation Affiliation)
93	{
94		//if (!BorderImage) return;
95	
96		FLinearColor HealthColor;
97		switch (Affiliation)
98		{
99		case EUnitAffiliation::UA_Player:
100			HealthColor = PlayerColor;
101			break;
102		case EUnitAffiliation::UA_Enemy:
103			HealthColor = EnemyColor;
104			break;
105		case EUnitAffiliation::UA_Neutral:
106			HealthColor = NeutralColor;
107			break;
108		default:
109			HealthColor = FLinearColor::White;
110		}
111	
112		//BorderImage->SetColorAndOpacity(BorderColor);
