## 19. Complete Widget Structure Template

Here's a minimal template showing all the standard patterns:

```cpp
// .h file
UCLASS()
class LFP2D_API ULFPMyWidget : public UUserWidget
{
    GENERATED_BODY()

public:
    UFUNCTION(BlueprintCallable, Category = "MyWidget")
    void Setup(const FMyDataDefinition& InData);

    UPROPERTY(BlueprintAssignable)
    FOnMyWidgetClosed OnClosed;

protected:
    virtual void NativeOnInitialized() override;

private:
    void RefreshUI();

    UFUNCTION() void OnButtonClicked();
    UFUNCTION() void OnCloseClicked();

    // BindWidget elements
    UPROPERTY(BlueprintReadOnly, meta = (BindWidgetOptional))
    TObjectPtr<UTextBlock> Text_Title;

    UPROPERTY(BlueprintReadOnly, meta = (BindWidgetOptional))
    TObjectPtr<UButton> Button_Close;

    // Cached data
    FMyDataDefinition CachedData;
};

// .cpp file
void ULFPMyWidget::NativeOnInitialized()
{
    Super::NativeOnInitialized();

    if (Button_Close) Button_Close->OnClicked.AddDynamic(this, &ULFPMyWidget::OnCloseClicked);
}

void ULFPMyWidget::Setup(const FMyDataDefinition& InData)
{
    CachedData = InData;
    RefreshUI();
}

void ULFPMyWidget::RefreshUI()
{
    if (Text_Title) Text_Title->SetText(CachedData.DisplayName);
}

void ULFPMyWidget::OnCloseClicked()
{
    SetVisibility(ESlateVisibility::Collapsed);
    RemoveFromParent();
    OnClosed.Broadcast();
}
```

